import{_ as e,o as t,c as o,a4 as i}from"./chunks/framework.CDpUjPX_.js";const u=JSON.parse('{"title":"Plano de Resposta a Incidentes de Segurança — Kubex","description":"","frontmatter":{},"headers":[],"relativePath":"seguranca/incident-response-plan.md","filePath":"seguranca/incident-response-plan.md"}'),s={name:"seguranca/incident-response-plan.md"};function r(d,a,n,l,c,h){return t(),o("div",null,[...a[0]||(a[0]=[i(`<h1 id="plano-de-resposta-a-incidentes-de-seguranca-—-kubex" tabindex="-1">Plano de Resposta a Incidentes de Segurança — Kubex <a class="header-anchor" href="#plano-de-resposta-a-incidentes-de-seguranca-—-kubex" aria-label="Permalink to &quot;Plano de Resposta a Incidentes de Segurança — Kubex&quot;">​</a></h1><p><strong>Versão:</strong> 1.0 <strong>Última revisão:</strong> 2026-03-27 <strong>Responsável:</strong> Renato (CEO / DPO) <strong>Base legal:</strong> LGPD Art. 46, 48, 50</p><hr><h2 id="_1-objetivo" tabindex="-1">1. Objetivo <a class="header-anchor" href="#_1-objetivo" aria-label="Permalink to &quot;1. Objetivo&quot;">​</a></h2><p>Este plano estabelece os procedimentos para detecção, contenção, erradicação e recuperação de incidentes de segurança da informação na plataforma Kubex, com foco especial na proteção de dados pessoais conforme exigido pela LGPD (Lei Geral de Proteção de Dados — Lei nº 13.709/2018).</p><p>A Kubex processa dados sensíveis incluindo:</p><ul><li><strong>Dados biométricos:</strong> embeddings faciais (Milvus), imagens para reconhecimento facial (AdaFace, DeepFace)</li><li><strong>Dados pessoais:</strong> CPF/CNPJ, e-mail, nome, endereço IP</li><li><strong>Dados de navegação:</strong> URLs monitoradas, resultados de varredura dos 27 motores de detecção</li><li><strong>Credenciais:</strong> hashes bcrypt, tokens de sessão (httpOnly cookies)</li></ul><hr><h2 id="_2-classificacao-de-incidentes" tabindex="-1">2. Classificação de Incidentes <a class="header-anchor" href="#_2-classificacao-de-incidentes" aria-label="Permalink to &quot;2. Classificação de Incidentes&quot;">​</a></h2><h3 id="critico-p1-—-resposta-imediata-1-hora" tabindex="-1">CRÍTICO (P1) — Resposta imediata (&lt; 1 hora) <a class="header-anchor" href="#critico-p1-—-resposta-imediata-1-hora" aria-label="Permalink to &quot;CRÍTICO (P1) — Resposta imediata (&lt; 1 hora)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Exemplo</th><th>Sistemas afetados</th></tr></thead><tbody><tr><td>Vazamento de embeddings faciais (Milvus)</td><td>Milvus, PostgreSQL, R2</td></tr><tr><td>Acesso não autorizado ao banco de dados de produção</td><td>PostgreSQL, async_session</td></tr><tr><td>Comprometimento de credenciais de acesso (API keys, tokens)</td><td>Redis, .env, Celery broker</td></tr><tr><td>Ransomware ou destruição de dados</td><td>Todos os sistemas</td></tr><tr><td>Exploração ativa de vulnerabilidade (RCE, SQL injection)</td><td>FastAPI, PostgreSQL</td></tr><tr><td>Vazamento massivo de PII (CPF, CNPJ, dados de usuários)</td><td>PostgreSQL, audit_logs</td></tr></tbody></table><h3 id="alto-p2-—-resposta-em-ate-4-horas" tabindex="-1">ALTO (P2) — Resposta em até 4 horas <a class="header-anchor" href="#alto-p2-—-resposta-em-ate-4-horas" aria-label="Permalink to &quot;ALTO (P2) — Resposta em até 4 horas&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Exemplo</th><th>Sistemas afetados</th></tr></thead><tbody><tr><td>Acesso não autorizado a painel administrativo</td><td>frontend-admin, auth cookies</td></tr><tr><td>Bypass de autenticação ou escalação de privilégios</td><td>FastAPI auth, get_admin_user</td></tr><tr><td>Falha no circuit breaker expondo APIs externas</td><td>app/core/circuit_breaker.py</td></tr><tr><td>Comprometimento de worker Celery</td><td>Celery, Redis broker</td></tr><tr><td>SSRF bypass no crawler engine</td><td>app/engines/crawler/</td></tr><tr><td>Exposição de dados via API sem autenticação</td><td>FastAPI routes</td></tr></tbody></table><h3 id="medio-p3-—-resposta-em-ate-24-horas" tabindex="-1">MÉDIO (P3) — Resposta em até 24 horas <a class="header-anchor" href="#medio-p3-—-resposta-em-ate-24-horas" aria-label="Permalink to &quot;MÉDIO (P3) — Resposta em até 24 horas&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Exemplo</th><th>Sistemas afetados</th></tr></thead><tbody><tr><td>Falha persistente em motor de detecção (health check)</td><td>Motor Registry, Sentinel</td></tr><tr><td>Rate limiting ineficaz (DDoS parcial)</td><td>slowapi, Redis, Nginx</td></tr><tr><td>Logs contendo PII indevidamente</td><td>logging, audit_logs</td></tr><tr><td>Certificado SSL próximo ao vencimento</td><td>Nginx, kubex.com.br</td></tr><tr><td>Vulnerabilidade em dependência (pip-audit/npm audit)</td><td>requirements.txt, package.json</td></tr></tbody></table><h3 id="baixo-p4-—-resposta-em-ate-72-horas" tabindex="-1">BAIXO (P4) — Resposta em até 72 horas <a class="header-anchor" href="#baixo-p4-—-resposta-em-ate-72-horas" aria-label="Permalink to &quot;BAIXO (P4) — Resposta em até 72 horas&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Exemplo</th><th>Sistemas afetados</th></tr></thead><tbody><tr><td>Tentativas de login brute-force (bloqueadas)</td><td>slowapi, audit_logs</td></tr><tr><td>Scan de portas detectado</td><td>Nginx, Docker network</td></tr><tr><td>Falha intermitente em mock mode</td><td>Telegram mock, engines</td></tr><tr><td>Warning de segurança em header CSP</td><td>Nginx security headers</td></tr></tbody></table><hr><h2 id="_3-equipe-de-resposta" tabindex="-1">3. Equipe de Resposta <a class="header-anchor" href="#_3-equipe-de-resposta" aria-label="Permalink to &quot;3. Equipe de Resposta&quot;">​</a></h2><h3 id="papeis-e-responsabilidades" tabindex="-1">Papéis e Responsabilidades <a class="header-anchor" href="#papeis-e-responsabilidades" aria-label="Permalink to &quot;Papéis e Responsabilidades&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Papel</th><th>Responsável</th><th>Responsabilidades</th></tr></thead><tbody><tr><td><strong>Coordenador de Incidentes / DPO</strong></td><td>Renato (CEO)</td><td>Decisão final, comunicação com ANPD, notificação a titulares, aprovação de ações destrutivas</td></tr><tr><td><strong>Security Agent</strong></td><td>Agente IA KAAS</td><td>Detecção de vulnerabilidades, scan de dependências, verificação OWASP, análise de logs</td></tr><tr><td><strong>Backend Agent</strong></td><td>Agente IA KAAS</td><td>Correções de código, patches de segurança, rollback de deploys</td></tr><tr><td><strong>SRE Agent</strong></td><td>Agente IA KAAS</td><td>Health checks dos 27 motores, Sentinel monitoring, circuit breakers</td></tr><tr><td><strong>Director Agent</strong></td><td>Agente IA KAAS</td><td>Orquestração entre agentes, priorização, escalonamento</td></tr></tbody></table><h3 id="escalonamento" tabindex="-1">Escalonamento <a class="header-anchor" href="#escalonamento" aria-label="Permalink to &quot;Escalonamento&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agente detecta problema → Director Agent avalia severidade</span></span>
<span class="line"><span>  → P3/P4: Agente resolve e reporta</span></span>
<span class="line"><span>  → P1/P2: Notifica CEO IMEDIATAMENTE + Agente inicia contenção</span></span></code></pre></div><hr><h2 id="_4-procedimento-de-resposta" tabindex="-1">4. Procedimento de Resposta <a class="header-anchor" href="#_4-procedimento-de-resposta" aria-label="Permalink to &quot;4. Procedimento de Resposta&quot;">​</a></h2><h3 id="_4-1-deteccao-e-triagem-todas-as-severidades" tabindex="-1">4.1 Detecção e Triagem (todas as severidades) <a class="header-anchor" href="#_4-1-deteccao-e-triagem-todas-as-severidades" aria-label="Permalink to &quot;4.1 Detecção e Triagem (todas as severidades)&quot;">​</a></h3><ol><li><strong>Identificar a fonte:</strong> log de auditoria, alerta do Sentinel (Motor 27), health check, pip-audit, monitoramento externo</li><li><strong>Classificar a severidade</strong> conforme Seção 2</li><li><strong>Registrar o incidente:</strong><ul><li>Data/hora de detecção</li><li>Descrição técnica</li><li>Sistemas afetados</li><li>Dados pessoais potencialmente expostos</li><li>Severidade atribuída</li></ul></li><li><strong>Notificar a equipe</strong> conforme a severidade</li></ol><h3 id="_4-2-contencao" tabindex="-1">4.2 Contencao <a class="header-anchor" href="#_4-2-contencao" aria-label="Permalink to &quot;4.2 Contencao&quot;">​</a></h3><h4 id="p1-critico" tabindex="-1">P1 (CRITICO) <a class="header-anchor" href="#p1-critico" aria-label="Permalink to &quot;P1 (CRITICO)&quot;">​</a></h4><ol><li>Isolar servico comprometido: <code>docker stop kubex-api</code> (ou container afetado)</li><li>Se Milvus comprometido: <code>docker stop kubex-milvus</code></li><li>Revogar credenciais — rotacionar SECRET_KEY, DATABASE_URL, REDIS_URL em <code>.env</code></li><li>Bloquear IPs suspeitos via <code>nginx/default.conf</code></li><li>Preservar evidencias: <code>docker logs kubex-api &gt; /tmp/incident_$(date +%Y%m%d_%H%M%S).log</code></li></ol><h4 id="p2-alto" tabindex="-1">P2 (ALTO) <a class="header-anchor" href="#p2-alto" aria-label="Permalink to &quot;P2 (ALTO)&quot;">​</a></h4><ol><li>Invalidar sessoes: limpar tokens no Redis (<code>KEYS &quot;kubex:session:*&quot;</code>)</li><li>Ativar rate limiting agressivo temporariamente</li><li>Verificar audit_logs da ultima hora</li></ol><h4 id="p3-p4-medio-baixo" tabindex="-1">P3/P4 (MEDIO/BAIXO) <a class="header-anchor" href="#p3-p4-medio-baixo" aria-label="Permalink to &quot;P3/P4 (MEDIO/BAIXO)&quot;">​</a></h4><ol><li>Documentar o problema</li><li>Aplicar correcao ou workaround</li><li>Agendar correcao definitiva</li></ol><h3 id="_4-3-erradicacao" tabindex="-1">4.3 Erradicação <a class="header-anchor" href="#_4-3-erradicacao" aria-label="Permalink to &quot;4.3 Erradicação&quot;">​</a></h3><ol><li><strong>Identificar a causa raiz</strong> — análise de logs, code review, scan de vulnerabilidades</li><li><strong>Remover o vetor de ataque:</strong><ul><li>Patch de código (branch <code>kaas/security/incident-{id}</code>)</li><li>Atualização de dependências vulneráveis</li><li>Correção de configuração</li></ul></li><li><strong>Verificar que não há persistência:</strong><ul><li>Verificar crontabs e scheduled tasks</li><li>Verificar se não há backdoor em código</li><li>Scan com <code>pip-audit</code> e <code>npm audit</code></li></ul></li><li><strong>Rotacionar TODAS as credenciais</strong> se houve comprometimento de acesso</li></ol><h3 id="_4-4-recuperacao" tabindex="-1">4.4 Recuperação <a class="header-anchor" href="#_4-4-recuperacao" aria-label="Permalink to &quot;4.4 Recuperação&quot;">​</a></h3><ol><li><strong>Restaurar serviços</strong> na ordem: <ul><li>PostgreSQL → Redis → FastAPI (api) → Celery workers → Nginx → Frontends</li></ul></li><li><strong>Verificar integridade:</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Health check dos motores</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pytest</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;not slow&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ruff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app/</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Verificar Sentinel</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8000/api/v1/sentinel/health</span></span></code></pre></div></li><li><strong>Monitorar por 24-48 horas</strong> após restauração</li><li><strong>Validar que dados LGPD não persistiram indevidamente:</strong><ul><li>Confirmar <code>del img_bytes</code> em todas as tasks</li><li>Verificar que não há PII em logs</li></ul></li></ol><h3 id="_4-5-comunicacao" tabindex="-1">4.5 Comunicação <a class="header-anchor" href="#_4-5-comunicacao" aria-label="Permalink to &quot;4.5 Comunicação&quot;">​</a></h3><h4 id="comunicacao-interna" tabindex="-1">Comunicação Interna <a class="header-anchor" href="#comunicacao-interna" aria-label="Permalink to &quot;Comunicação Interna&quot;">​</a></h4><ul><li>P1/P2: CEO notificado imediatamente (WhatsApp, e-mail)</li><li>P3/P4: Relatório no próximo ciclo de revisão</li></ul><h4 id="comunicacao-externa-ver-secao-5-para-prazos-lgpd" tabindex="-1">Comunicação Externa (ver Seção 5 para prazos LGPD) <a class="header-anchor" href="#comunicacao-externa-ver-secao-5-para-prazos-lgpd" aria-label="Permalink to &quot;Comunicação Externa (ver Seção 5 para prazos LGPD)&quot;">​</a></h4><ul><li>ANPD: obrigatório para incidentes envolvendo dados pessoais</li><li>Titulares: obrigatório quando há risco relevante aos direitos</li></ul><hr><h2 id="_5-prazos-lgpd-art-48" tabindex="-1">5. Prazos LGPD (Art. 48) <a class="header-anchor" href="#_5-prazos-lgpd-art-48" aria-label="Permalink to &quot;5. Prazos LGPD (Art. 48)&quot;">​</a></h2><h3 id="notificacao-a-anpd" tabindex="-1">Notificação à ANPD <a class="header-anchor" href="#notificacao-a-anpd" aria-label="Permalink to &quot;Notificação à ANPD&quot;">​</a></h3><p>A LGPD (Art. 48, §1º) determina que o controlador deve comunicar à Autoridade Nacional de Proteção de Dados (ANPD) e ao titular a ocorrência de incidente de segurança que possa acarretar <strong>risco ou dano relevante</strong> aos titulares.</p><p><strong>Prazo:</strong> A ANPD recomenda comunicação em até <strong>2 dias úteis</strong> a partir do conhecimento do incidente (Resolução CD/ANPD nº 15/2024).</p><h3 id="quando-notificar-a-anpd" tabindex="-1">Quando notificar a ANPD <a class="header-anchor" href="#quando-notificar-a-anpd" aria-label="Permalink to &quot;Quando notificar a ANPD&quot;">​</a></h3><p>Notificar OBRIGATORIAMENTE quando o incidente envolver:</p><ul><li>Dados pessoais sensíveis (biométricos — embeddings faciais)</li><li>Dados de crianças/adolescentes</li><li>Dados que possam causar dano material ou moral significativo</li><li>Grande volume de titulares afetados</li></ul><h3 id="conteudo-da-notificacao-art-48-§1o" tabindex="-1">Conteúdo da notificação (Art. 48, §1º) <a class="header-anchor" href="#conteudo-da-notificacao-art-48-§1o" aria-label="Permalink to &quot;Conteúdo da notificação (Art. 48, §1º)&quot;">​</a></h3><p>A comunicação deve conter, no mínimo:</p><ol><li>Descrição da natureza dos dados pessoais afetados</li><li>Informações sobre os titulares envolvidos</li><li>Indicação das medidas técnicas e de segurança utilizadas</li><li>Riscos relacionados ao incidente</li><li>Motivos da demora, se não comunicado imediatamente</li><li>Medidas adotadas para reverter ou mitigar os efeitos</li></ol><h3 id="notificacao-aos-titulares" tabindex="-1">Notificação aos Titulares <a class="header-anchor" href="#notificacao-aos-titulares" aria-label="Permalink to &quot;Notificação aos Titulares&quot;">​</a></h3><p>Quando o incidente puder acarretar risco ou dano relevante, os titulares devem ser notificados com:</p><ul><li>Descrição clara e acessível do ocorrido</li><li>Tipos de dados afetados</li><li>Medidas tomadas</li><li>Recomendações ao titular (troca de senha, monitoramento)</li><li>Canal de contato do DPO/Encarregado</li></ul><hr><h2 id="_6-templates-de-notificacao" tabindex="-1">6. Templates de Notificacao <a class="header-anchor" href="#_6-templates-de-notificacao" aria-label="Permalink to &quot;6. Templates de Notificacao&quot;">​</a></h2><h3 id="_6-1-template-—-notificacao-a-anpd" tabindex="-1">6.1 Template — Notificacao a ANPD <a class="header-anchor" href="#_6-1-template-—-notificacao-a-anpd" aria-label="Permalink to &quot;6.1 Template — Notificacao a ANPD&quot;">​</a></h3><p>Conteudo minimo (Art. 48, par.1):</p><ol><li><strong>Identificacao do controlador</strong> — Razao social, CNPJ, DPO (Renato)</li><li><strong>Descricao do incidente</strong> — Data, tipo (acesso nao autorizado / vazamento / perda)</li><li><strong>Dados pessoais afetados</strong> — Tipos (nome, CPF, biometricos), volume de titulares</li><li><strong>Medidas de seguranca pre-existentes</strong> — httpOnly cookies, bcrypt, rate limiting, SSRF guard, LGPD (del img_bytes), circuit breakers, audit logs</li><li><strong>Riscos aos titulares</strong></li><li><strong>Medidas adotadas para contencao/mitigacao</strong></li><li><strong>Assinatura</strong> — Renato (DPO / CEO), data</li></ol><h3 id="_6-2-template-—-notificacao-aos-titulares" tabindex="-1">6.2 Template — Notificacao aos Titulares <a class="header-anchor" href="#_6-2-template-—-notificacao-aos-titulares" aria-label="Permalink to &quot;6.2 Template — Notificacao aos Titulares&quot;">​</a></h3><p>Conteudo minimo:</p><ol><li><strong>O que aconteceu</strong> — Descricao em linguagem acessivel</li><li><strong>Dados afetados</strong> — Lista dos tipos de dados</li><li><strong>Acoes tomadas</strong> — Medidas tecnicas e organizacionais</li><li><strong>Recomendacoes</strong> — Alterar senha, monitorar contas, desconfiar de comunicacoes suspeitas</li><li><strong>Canal de contato</strong> — Email e telefone do DPO</li></ol><hr><h2 id="_7-contatos-de-emergencia" tabindex="-1">7. Contatos de Emergência <a class="header-anchor" href="#_7-contatos-de-emergencia" aria-label="Permalink to &quot;7. Contatos de Emergência&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Papel</th><th>Nome</th><th>Contato</th><th>Disponibilidade</th></tr></thead><tbody><tr><td>CEO / DPO</td><td>Renato</td><td>[EMAIL] / [TELEFONE]</td><td>24/7 para P1</td></tr><tr><td>Hosting/Infra</td><td>[PROVEDOR]</td><td>[CONTATO]</td><td>Conforme SLA</td></tr><tr><td>ANPD</td><td>Autoridade Nacional</td><td><a href="https://www.gov.br/anpd" target="_blank" rel="noreferrer">https://www.gov.br/anpd</a></td><td>Horário comercial</td></tr><tr><td>CERT.br</td><td>Centro de Resposta</td><td><a href="mailto:cert@cert.br" target="_blank" rel="noreferrer">cert@cert.br</a> / <a href="https://www.cert.br" target="_blank" rel="noreferrer">https://www.cert.br</a></td><td>24/7</td></tr></tbody></table><blockquote><p><strong>AÇÃO NECESSÁRIA:</strong> Preencher os campos entre colchetes com dados reais antes de publicar este plano.</p></blockquote><hr><h2 id="_8-pos-incidente" tabindex="-1">8. Pós-Incidente <a class="header-anchor" href="#_8-pos-incidente" aria-label="Permalink to &quot;8. Pós-Incidente&quot;">​</a></h2><h3 id="analise-post-mortem" tabindex="-1">Análise Post-Mortem <a class="header-anchor" href="#analise-post-mortem" aria-label="Permalink to &quot;Análise Post-Mortem&quot;">​</a></h3><p>Após a resolução de qualquer incidente P1 ou P2, realizar análise post-mortem contendo:</p><ol><li><strong>Timeline completa</strong> — desde a primeira evidência até a resolução</li><li><strong>Causa raiz</strong> — análise técnica detalhada</li><li><strong>Impacto real</strong> — dados afetados, titulares impactados, duração</li><li><strong>Eficácia da resposta</strong> — o que funcionou, o que precisa melhorar</li><li><strong>Ações corretivas</strong> — lista de melhorias com prazos e responsáveis</li></ol><h3 id="licoes-aprendidas" tabindex="-1">Lições Aprendidas <a class="header-anchor" href="#licoes-aprendidas" aria-label="Permalink to &quot;Lições Aprendidas&quot;">​</a></h3><ul><li>Atualizar este plano com base nos achados</li><li>Implementar controles adicionais identificados</li><li>Treinar equipe (humana e agentes IA) sobre novos procedimentos</li></ul><hr><h2 id="_9-revisao-do-plano" tabindex="-1">9. Revisão do Plano <a class="header-anchor" href="#_9-revisao-do-plano" aria-label="Permalink to &quot;9. Revisão do Plano&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Frequência</th></tr></thead><tbody><tr><td>Revisão completa do plano</td><td>Semestral</td></tr><tr><td>Teste/simulação de incidente</td><td>Trimestral</td></tr><tr><td>Atualização de contatos</td><td>Mensal</td></tr><tr><td>Revisão pós-incidente real</td><td>Após cada P1/P2</td></tr></tbody></table><h3 id="historico-de-revisoes" tabindex="-1">Histórico de Revisões <a class="header-anchor" href="#historico-de-revisoes" aria-label="Permalink to &quot;Histórico de Revisões&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Versão</th><th>Data</th><th>Autor</th><th>Descrição</th></tr></thead><tbody><tr><td>1.0</td><td>2026-03-27</td><td>Renato (CEO)</td><td>Versão inicial do plano</td></tr></tbody></table>`,81)])])}const m=e(s,[["render",r]]);export{u as __pageData,m as default};
